for (let item of $input.all()) {
  let html = item.json.output || ""; 
  if (!html) continue;

  // 1. 去除大模型生成的 ```html 标记
  html = html.replace(/```html/gi, '').replace(/```/g, '');

  // 2. 转换加粗为 WhatsApp 格式
  let text = html.replace(/<strong[^>]*>(.*?)<\/strong>/gi, '*$1*');
  text = text.replace(/<b[^>]*>(.*?)<\/b>/gi, '*$1*');

  // 3. 遇到段落、换行、标题、表格行，转换为换行符
  text = text.replace(/<br\s*[\/]?>|<\/p>|<\/div>|<\/h[1-6]>|<\/tr>/gi, '\n');

  // 4. 表格列对齐 (用2个空格隔开)
  text = text.replace(/<\/td>|<\/th>/gi, '  ');

  // 5. 暴力扒皮：无差别抹掉所有剩下的 < > 标签，处理 &nbsp;
  text = text.replace(/<[^>]+>/g, '');
  text = text.replace(/&nbsp;/g, ' ');

  // ==========================================
  // 🚀 核心修复：真空压缩排版 (专门对付多余空行)
  // ==========================================

  // a. 把所有横向连续的空格/Tab压缩为一个空格
  text = text.replace(/[ \t]+/g, ' '); 

  // b. 【关键】剔除每一行开头和结尾的多余空格！(这样带空格的空行就会变成纯空行)
  text = text.replace(/^[ \t]+|[ \t]+$/gm, '');

  // c. 放心大胆地把 3 个以上的连续换行压缩成最多 2 个 (完美保留段落间距)
  text = text.replace(/\n{3,}/g, '\n\n'); 

  // 把洗干净的极速文本存入新字段
  item.json.whatsapp_message = text.trim();
}

return $input.all();

// 获取来自 Merge 节点的所有原始行数据
const items = $input.all();
const reportMap = {};

for (const item of items) {
    const data = item.json;

    // 1. 标准化客户姓名
    let name = data['Customer Name'];
    if (!name) continue;
    name = name.toString().trim();

    // 2. 初始化客户结构（保留了 phone 和 sendChannel）
    if (!reportMap[name]) {
        reportMap[name] = {
            customerName: name,
            email: "",           
            phone: "",           
            sendChannel: "",
            storageItems: [],    
            shippingItems: [],   
            totalStorageFee: 0,
            totalLogisticsFee: 0
        };
    }

    // 3. 匹配联系方式与发送渠道逻辑（恢复原始逻辑）
    if (data['WhatsApp Number']) reportMap[name].phone = data['WhatsApp Number'].toString().trim();
    if (data['Email']) reportMap[name].email = data['Email'].toString().trim();

    if (reportMap[name].phone) {
        reportMap[name].sendChannel = "whatsapp";
    } else if (reportMap[name].email) {
        reportMap[name].sendChannel = "gmail";
    }

    // 4. 处理仓储费 (仅保留订单号和费用)
    if (data['Storage Fee Receivable (MYR)']) {
        const fee = parseFloat(data['Storage Fee Receivable (MYR)']) || 0;
        reportMap[name].totalStorageFee += fee;
        reportMap[name].storageItems.push({
            "orderNo": data['Order No.'],
            "fee": fee.toFixed(2)
        });
    }

    // 5. 处理物流费 (仅保留出库单号和费用)
    if (data['Receivable Logistics Price']) {
        const price = parseFloat(data['Receivable Logistics Price']) || 0;
        reportMap[name].totalLogisticsFee += price;
        reportMap[name].shippingItems.push({
            "outboundNo": data['Outbound Order No.'],
            "fee": price.toFixed(2)
        });
    }
}

// 6. 最终输出
return Object.values(reportMap).map(data => {
    return {
        json: {
            ...data, // 展开所有字段，包括 phone 和 sendChannel
            totalStorageSum: data.totalStorageFee.toFixed(2),
            totalLogisticsSum: data.totalLogisticsFee.toFixed(2),
            grandTotal: (data.totalStorageFee + data.totalLogisticsFee).toFixed(2),
            reportDate: new Date().toLocaleDateString('en-US', { year: 'numeric', month: 'long' })
        }
    };
});

