for (const item of $input.all()) {
  const raw = item.json.output || '';
  let clean = raw;
  let action = 'A'; // 默认保底
  let complaintReason = ''; // 🌟 新增：默认客诉原因设为空

  // 1. 暴力清除回复给用户的内容：只要遇到 ---，后面的全部砍掉
  const splitParts = raw.split('---');
  clean = splitParts[0].trim();
  // 万一它没写 ---，也强行把大括号及后面的代码砍掉
  if (splitParts.length === 1) {
     const braceIndex = clean.lastIndexOf('{');
     if (braceIndex !== -1) clean = clean.substring(0, braceIndex).trim();
  }
  // 清理残留的 markdown 代码块符号
  clean = clean.replace(/```json/gi, '').replace(/```/gi, '').trim();

  // 2. 暴力提取背后的动作指令及附加数据
  try {
    const match = raw.match(/\{[\s\S]*\}/);
    if (match) {
       const parsed = JSON.parse(match[0]);

       // 提取动作 Action
       if (parsed.action) {
           action = String(parsed.action).trim().toUpperCase();
       }

       // 🌟 新增：精准提取客诉原因
       if (parsed.complaint_reason) {
           complaintReason = String(parsed.complaint_reason).trim();
       }
    }
  } catch (e) {
    console.log('JSON 解析失败');
  }

  // 3. 把所有干净的数据打包，发往下一站 (Google Sheets / 发送节点)
  item.json.cleanReply = clean;
  item.json.action = action;
  item.json.rawOutput = raw;
  item.json.complaint_reason = complaintReason; // 🌟 新增：将原因暴露给后面的节点
}
return $input.all();

