const src = $json || {};

// AI text output (compatible with different AI node fields)
const aiText = String(
  src.output ??
  src.text ??
  src.response ??
  src.content ??
  src.message ??
  ''
);

function e(s) {
  return String(s ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;');
}

function pick(tag) {
  const re = new RegExp(`\\[${tag}\\]([\\s\\S]*?)\\[\\/${tag}\\]`, 'i');
  const m = aiText.match(re);
  return m ? m[1].trim() : '';
}

function parseList(text) {
  return String(text || '')
    .split(/\r?\n+/)
    .map(x => x.replace(/^[\-\d\.\)\s、]+/, '').trim())
    .filter(Boolean)
    .slice(0, 3);
}

const deptName = src.deptName || src.dept || '';
const week = src.week || '';
const charts = Array.isArray(src.charts) ? src.charts : [];

const o = pick('O');
const c1 = pick('C1');
const c2 = pick('C2');
const c3 = pick('C3');
const s = pick('S');
const r = parseList(pick('R'));

const txt = [c1, c2, c3];

const chartHtml = charts.map((c, i) => `
  <div style="margin:20px 0;padding:16px;border:1px solid #e5e7eb;border-radius:10px;">
    <h3 style="margin:0 0 12px;">${e(c.title || '')}</h3>
    <img src="${e(c.url || '')}" style="max-width:100%;border-radius:8px;">
    <p style="font-size:14px;line-height:1.8;">${e(txt[i] || '')}</p>
  </div>
`).join('');

const rec = r.map(x => `<li>${e(x)}</li>`).join('');

const html = `
<div style="max-width:900px;margin:0 auto;padding:24px;background:#f7f7f7;font-family:Arial;">
  <div style="background:#fff;padding:24px;border-radius:12px;">
    <h1 style="margin:0 0 8px;">${e(deptName)} Weekly Report</h1>
    <p style="margin:0 0 16px;color:#666;">Period: ${e(week)}</p>

    <h2 style="font-size:18px;">Overview</h2>
    <p style="font-size:14px;line-height:1.8;">${e(o)}</p>

    ${chartHtml}

    <h2 style="font-size:18px;">Overall Analysis</h2>
    <p style="font-size:14px;line-height:1.8;">${e(s)}</p>

    <h2 style="font-size:18px;">Recommendations</h2>
    <ol style="font-size:14px;line-height:1.8;">${rec}</ol>
  </div>
</div>`;

const realToMap = {
  '仓库': '15005150310@163.com',
  '财务': '17328235049@163.com',
  '物流': 'yinpenghua@outlook.com',
  '客服': 'yinpenghua@outlook.com',
  'warehouse': '15005150310@163.com',
  'finance': '17328235049@163.com',
  'logistics': 'yinpenghua@outlook.com',
  'customer': 'yinpenghua@outlook.com',
};

const rawTo = src.to || '';
const to = (!rawTo || /@example\.com$/i.test(rawTo))
  ? (realToMap[src.dept] || realToMap[src.deptName] || '')
  : rawTo;

const subject = src.subject || `${deptName} Weekly Report｜${week}`;

return {
  json: {
    to,
    subject,
    html
  }
};

const inbound = $items('Inbound').map(i => i.json);
const outbound = $items('outbound').map(i => i.json);
const shipping = $items('Logistics').map(i => i.json);
const feedback = $items('Agent_Feedback').map(i => i.json);

const mail = {
  warehouse: '15005150310@163.com',
  finance: '17328235049@163.com',
  logistics: 'yinpenghua@outlook.com',
  customer: '2372290190@qq.com',
};

const n = v => {
  if (v === null || v === undefined || v === '') return 0;
  return +String(v).replace(/,/g, '') || 0;
};

const d = v => {
  if (v === '' || v == null) return null;

  if (typeof v === 'number') {
    return new Date((v - 25569) * 86400 * 1000);
  }

  if (v instanceof Date) {
    return isNaN(v) ? null : v;
  }

  const s = String(v).trim();

  const m = s.match(/^(\d{1,2})\/(\d{1,2})\/(\d{4})(.*)$/);
  if (m) {
    const day = m[1].padStart(2, '0');
    const month = m[2].padStart(2, '0');
    const year = m[3];
    const rest = m[4] || '';
    const x = new Date(`${year}-${month}-${day}${rest}`);
    return isNaN(x) ? null : x;
  }

  const x = new Date(s);
  return isNaN(x) ? null : x;
};

const ds = x => x
  ? `${x.getFullYear()}-${String(x.getMonth() + 1).padStart(2, '0')}-${String(x.getDate()).padStart(2, '0')}`
  : '';

const allDates = [
  ...inbound.map(r => d(r['Receipt Time'])).filter(Boolean),
  ...outbound.map(r => d(r['Outbound Date'])).filter(Boolean),
  ...shipping.map(r => d(r['Outbound Time'])).filter(Boolean),
  ...feedback.map(r => d(r['  Time'])).filter(Boolean),
];

const latestDate = allDates.length
  ? new Date(Math.max(...allDates.map(x => x.getTime())))
  : new Date();

const latestDay = new Date(latestDate);
latestDay.setHours(0, 0, 0, 0);

const start = new Date(latestDay);
start.setDate(latestDay.getDate() - 6);

const endExclusive = new Date(latestDay);
endExclusive.setDate(latestDay.getDate() + 1);

const week = `${ds(start)} ~ ${ds(latestDay)}`;

const inWeek = v => {
  const x = d(v);
  return x && x >= start && x < endExclusive;
};

const days = Array.from({ length: 7 }, (_, i) => {
  const x = new Date(start);
  x.setDate(start.getDate() + i);
  return ds(x);
});

const daySum = (rows, t, k) =>
  days.map(day =>
    rows
      .filter(r => inWeek(r[t]) && ds(d(r[t])) === day)
      .reduce((s, r) => s + n(r[k]), 0)
  );

const grpSum = (rows, g, k, t) =>
  Object.entries(
    rows.reduce((m, r) => {
      if (t && !inWeek(r[t])) return m;
      const x = String(r[g] || 'Unknown').trim() || 'Unknown';
      m[x] = (m[x] || 0) + n(r[k]);
      return m;
    }, {})
  ).sort((a, b) => b[1] - a[1]);

const grpCnt = (rows, g, t, key) =>
  Object.entries(
    rows.reduce((m, r) => {
      if (t && !inWeek(r[t])) return m;
      if (key && !r[key]) return m;
      const x = String(r[g] || 'Unknown').trim() || 'Unknown';
      m[x] = (m[x] || 0) + 1;
      return m;
    }, {})
  ).sort((a, b) => b[1] - a[1]);

const sum = a => Math.round(a.reduce((s, x) => s + n(x), 0) * 100) / 100;

const peak = a => {
  if (!a.length) return 'None';
  const m = Math.max(...a);
  return `${days[a.indexOf(m)]}(${Math.round(m * 100) / 100})`;
};

const top = (a, k = 3) =>
  a.slice(0, k).map(x => `${x[0]}:${Math.round(x[1] * 100) / 100}`).join('; ') || 'None';

const top10 = a =>
  a.length > 10
    ? [...a.slice(0, 10), ['Others', a.slice(10).reduce((s, x) => s + n(x[1]), 0)]]
    : a;

const chart = c =>
  `https://quickchart.io/chart?w=720&h=360&c=${encodeURIComponent(JSON.stringify(c))}`;

/* Warehouse */
const inDaily = daySum(inbound, 'Receipt Time', 'Qty Stocked In');
const outDaily = daySum(outbound, 'Outbound Date', 'Outbound Qty');
const outType = grpSum(outbound, 'Outbound Type', 'Outbound Qty', 'Outbound Date');

/* Finance */
const inCost = daySum(inbound, 'Receipt Time', 'Total Cost (RM)');
const outCost = daySum(outbound, 'Outbound Date', 'Logistics Subtotal / RM');
const shipCost = daySum(shipping, 'Outbound Time', 'Shipping Cost (RM)');

/* Logistics */
const carrierCnt = grpCnt(shipping, 'Carrier', 'Outbound Time', 'Tracking No.');
const carrierQty = grpSum(shipping, 'Carrier', 'Quantity', 'Outbound Time');
const shipType = grpSum(shipping, 'Outbound Type', 'Quantity', 'Outbound Time');

/* Customer Service */
const fb = feedback.filter(r => inWeek(r['  Time']));
const reasonCnt = grpCnt(fb, 'Specfic reasons');
const custCnt = top10(grpCnt(fb, 'Mobile Number/ Group From '));

return [
  {
    json: {
      dept: 'warehouse',
      deptName: 'Warehouse',
      to: mail.warehouse,
      subject: `Warehouse Weekly Report｜${week}`,
      week,
      brief: `Total inbound ${sum(inDaily)}, total outbound ${sum(outDaily)}; inbound peak ${peak(inDaily)}, outbound peak ${peak(outDaily)}; outbound type top: ${top(outType)}.`,
      charts: [
        {
          title: 'Daily Inbound vs Outbound',
          url: chart({
            type: 'bar',
            data: {
              labels: days,
              datasets: [
                { label: 'Inbound', data: inDaily },
                { label: 'Outbound', data: outDaily }
              ]
            }
          })
        },
        {
          title: 'Outbound Type Distribution',
          url: chart({
            type: 'doughnut',
            data: {
              labels: outType.map(x => x[0]),
              datasets: [{ data: outType.map(x => x[1]) }]
            }
          })
        }
      ]
    }
  },
  {
    json: {
      dept: 'finance',
      deptName: 'Finance',
      to: mail.finance,
      subject: `Finance Weekly Report｜${week}`,
      week,
      brief: `Inbound cost ${sum(inCost)} RM; outbound cost ${sum(outCost)} RM; shipping cost ${sum(shipCost)} RM; inbound cost peak ${peak(inCost)}, outbound cost peak ${peak(outCost)}, shipping cost peak ${peak(shipCost)}.`,
      charts: [
        {
          title: 'Daily Inbound Cost Trend',
          url: chart({
            type: 'line',
            data: {
              labels: days,
              datasets: [
                { label: 'Inbound Cost', data: inCost, fill: false }
              ]
            }
          })
        },
        {
          title: 'Daily Outbound & Shipping Cost Trend',
          url: chart({
            type: 'line',
            data: {
              labels: days,
              datasets: [
                { label: 'Outbound Cost', data: outCost, fill: false },
                { label: 'Shipping Cost', data: shipCost, fill: false }
              ]
            }
          })
        }
      ]
    }
  },
  {
    json: {
      dept: 'logistics',
      deptName: 'Logistics',
      to: mail.logistics,
      subject: `Logistics Weekly Report｜${week}`,
      week,
      brief: `Total shipments ${carrierCnt.reduce((s, x) => s + n(x[1]), 0)}, total shipped quantity ${sum(carrierQty.map(x => x[1]))}; carrier shipment top: ${top(carrierCnt)}; carrier quantity top: ${top(carrierQty)}; outbound type quantity top: ${top(shipType)}.`,
      charts: [
        {
