  <div style="background:#fff;padding:28px;border-radius:0 0 16px 16px;">
    <div style="padding:18px 20px;background:#f9fafb;border-radius:12px;">
      <h2 style="margin:0 0 10px;font-size:20px;">Executive Summary</h2>
      <p style="margin:0;font-size:14px;line-height:1.9;color:#374151;">${e(execSummary)}</p>
    </div>

    <div style="display:flex;gap:16px;flex-wrap:wrap;margin-top:20px;">
      <div style="flex:1;min-width:280px;padding:18px;background:#eef6ff;border-radius:12px;">
        <h2 style="margin:0 0 10px;font-size:18px;">Highlights</h2>
        <ol style="margin:0;padding-left:20px;font-size:14px;line-height:1.9;color:#374151;">
          ${highlights.map(x => `<li>${e(x)}</li>`).join('')}
        </ol>
      </div>
      <div style="flex:1;min-width:280px;padding:18px;background:#fff4f4;border-radius:12px;">
        <h2 style="margin:0 0 10px;font-size:18px;">Key Risks</h2>
        <ol style="margin:0;padding-left:20px;font-size:14px;line-height:1.9;color:#374151;">
          ${risks.map(x => `<li>${e(x)}</li>`).join('')}
        </ol>
      </div>
    </div>

    <div style="margin-top:24px;padding:18px;background:#f9fafb;border-radius:12px;">
      <h2 style="margin:0 0 10px;font-size:18px;">Department Perspectives</h2>
      <p style="margin:0;white-space:pre-line;font-size:14px;line-height:1.9;color:#374151;">${e(deptView)}</p>
    </div>

    <div style="margin-top:24px;padding:18px;background:#eefaf0;border-radius:12px;">
      <h2 style="margin:0 0 10px;font-size:18px;">Executive Recommendations</h2>
      <ol style="margin:0;padding-left:20px;font-size:14px;line-height:1.9;color:#374151;">
        ${actions.map(x => `<li>${e(x)}</li>`).join('')}
      </ol>
    </div>

    ${deptSections}
  </div>
</div>`;

return {
  json: {
    to: src.to || '',
    subject: src.subject || `CEO Weekly Report Overview｜${week}`,
    html
  }
};
